"use client";
 
import { useState } from "react";
import CursorGlow from "../components/CursorGlow";
 
const BG_IMAGE = "data:image/jpeg;base64,";
const LOGO_IMAGE = "data:image/jpeg;base64,";
const SUPABASE_URL = "https://mcpclsfhfkweecmcnxaf.supabase.co";
const SUPABASE_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im1jcGNsc2ZoZmt3ZWVjbWNueGFmIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODA4NjE5ODQsImV4cCI6MjA5NjQzNzk4NH0.SUaZx5o7zt-rFjqVLSPBTlfrRdf0IMkiRcRFOofsjMI";
 
export default function ApplyWhitelist() {
  const [tasks, setTasks] = useState({ follow: false, rt: false, quote: false });
  const [twitter, setTwitter] = useState("");
  const [wallet, setWallet] = useState("");
  const [agree, setAgree] = useState(false);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState("");
  const [info, setInfo] = useState("");
  const [twitterErr, setTwitterErr] = useState(false);
  const [walletErr, setWalletErr] = useState(false);
 
  const toggleTask = (id: "follow" | "rt" | "quote") => {
    setTasks((prev) => ({ ...prev, [id]: !prev[id] }));
  };
 
  const tasksDone = Object.values(tasks).filter(Boolean).length;
  const progress = (tasksDone / 3) * 100;
 
  const handleSubmit = async () => {
    setError("");
    setInfo("");
    setTwitterErr(false);
    setWalletErr(false);
 
    if (!tasks.follow || !tasks.rt) {
      setError("Please complete the two required tasks (Follow & Like/Retweet) before applying.");
      return;
    }
 
    let valid = true;
    if (!twitter.trim()) { setTwitterErr(true); valid = false; }
    if (!wallet.trim() || wallet.trim().length < 10) { setWalletErr(true); valid = false; }
    if (!agree) { setError("Please agree to the terms before submitting."); return; }
    if (!valid) return;
 
    setLoading(true);
    setInfo("Sending your application...");
 
    try {
      const res = await fetch(SUPABASE_URL + "/rest/v1/whitelist", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          apikey: SUPABASE_KEY,
          Authorization: "Bearer " + SUPABASE_KEY,
          Prefer: "return=minimal",
        },
        body: JSON.stringify({
          twitter_handle: twitter.trim().replace(/^@/, ""),
          wallet_address: wallet.trim(),
          quoted_tweet: tasks.quote,
        }),
      });
 
      if (res.status === 201) {
        setSuccess(true);
      } else {
        let errMsg = "Submission failed (status " + res.status + ").";
        try {
          const err = await res.json();
          if (err.code === "23505") errMsg = "This wallet or X handle has already been submitted.";
          else if (err.message) errMsg = "Error: " + err.message;
        } catch (e) {}
        setError(errMsg);
        setInfo("");
      }
    } catch (e: any) {
      setError("Network error: " + e.message);
      setInfo("");
    } finally {
      setLoading(false);
    }
  };
 
  return (
    <div style={{ fontFamily: "'Barlow', sans-serif", background: "#0a0604", minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;700&family=Barlow:wght@300;400;500;600&display=swap');
        @import url('https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@latest/tabler-icons.min.css');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        .pw-task { display:flex;align-items:center;gap:14px;background:#1a0d08;border:0.5px solid #2e1a0e;border-radius:8px;padding:16px 18px;cursor:pointer;user-select:none;transition:border-color .2s; }
        .pw-task:hover { border-color: #5a2a10; }
        .pw-task.completed { border-color:#7a3a1a; }
        .pw-input { width:100%;background:#1a0d08;border:0.5px solid #2e1a0e;border-radius:8px;padding:14px 16px 14px 36px;font-family:'Barlow',sans-serif;font-size:14px;color:#fef5e4;outline:none;transition:border-color .2s; }
        .pw-input:focus { border-color:#c04010;box-shadow:0 0 0 2px rgba(192,64,16,.15); }
        .pw-input::placeholder { color:#3a2a1e; }
        .pw-submit { width:100%;padding:17px;background:#1a0d08;border:0.5px solid #c04010;border-radius:8px;color:#fef5e4;font-family:'Barlow',sans-serif;font-size:11px;font-weight:600;letter-spacing:5px;text-transform:uppercase;cursor:pointer;transition:background .2s; }
        .pw-submit:hover:not(:disabled) { background:#c04010; }
        .pw-submit:disabled { opacity:.5;cursor:not-allowed; }
        @keyframes spin { to { transform: rotate(360deg); } }
        .pw-spinner { display:inline-block;width:14px;height:14px;border:2px solid rgba(254,245,228,.3);border-top-color:#fef5e4;border-radius:50%;animation:spin .7s linear infinite;vertical-align:-3px;margin-right:8px; }
      `}</style>
      <CursorGlow />
 
      {/* HERO */}
      <div style={{ width:"100%", position:"relative", height:"260px", overflow:"hidden" }}>
        <img src={BG_IMAGE} alt="" aria-hidden="true" style={{ position:"absolute", inset:0, width:"100%", height:"100%", objectFit:"cover", objectPosition:"center top" }} />
        <div style={{ position:"absolute", inset:0, background:"linear-gradient(to bottom,rgba(6,2,1,.1) 0%,rgba(6,2,1,.72) 100%)" }} />
      </div>
 
      {/* BODY */}
      <div style={{ width:"100%", maxWidth:"900px", padding:"36px 24px 48px" }}>
        {!success ? (
          <div>
            {/* Section: Tasks */}
            <p style={{ fontSize:"10px", letterSpacing:"5px", textTransform:"uppercase", color:"#c8a050", fontWeight:600, marginBottom:"16px", display:"flex", alignItems:"center", gap:"14px" }}>
              Complete tasks to apply
              <span style={{ flex:1, height:"0.5px", background:"#2e1a0e" }} />
            </p>
 
            <div style={{ display:"flex", flexDirection:"column", gap:"10px", marginBottom:"18px" }}>
              {[
                { id:"follow" as const, icon:"ti-brand-x", title:"Follow @Pollosoneth", desc:"Follow the official Pollos account on X to stay updated", badge:"Required", badgeType:"required" },
                { id:"rt" as const, icon:"ti-repeat", title:"Like, retweet & tag a friend", desc:"Go to @Pollosoneth's profile · like + retweet the pinned post · tag a friend in the comments", badge:"Required", badgeType:"required" },
                { id:"quote" as const, icon:"ti-quote", title:"Quote the pinned tweet", desc:"Quote tweet the pinned post with your thoughts for a higher chance of guaranteed whitelist", badge:"+Bonus", badgeType:"bonus" },
              ].map((task) => (
                <div key={task.id} className={`pw-task ${tasks[task.id] ? "completed" : ""}`} onClick={() => toggleTask(task.id)}>
                  <div style={{ width:"24px", height:"24px", borderRadius:"50%", border:`1.5px solid ${tasks[task.id] ? "#c04010" : "#3a2010"}`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, fontSize:"12px", color: tasks[task.id] ? "#fef5e4" : "transparent", background: tasks[task.id] ? "#c04010" : "#120806", transition:"all .2s" }}>
                    <i className="ti ti-check" />
                  </div>
                  <div style={{ width:"38px", height:"38px", borderRadius:"50%", background: tasks[task.id] ? "#6a2808" : "#2a1408", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, fontSize:"17px", color:"#f0c040" }}>
                    <i className={`ti ${task.icon}`} />
                  </div>
                  <div style={{ flex:1 }}>
                    <p style={{ fontSize:"14px", fontWeight:600, color:"#fef5e4", marginBottom:"3px" }}>{task.title}</p>
                    <p style={{ fontSize:"12px", color:"#7a5a45", lineHeight:1.4 }}>{task.desc}</p>
                  </div>
                  <span style={{ fontSize:"9px", letterSpacing:"1.5px", textTransform:"uppercase", padding:"4px 10px", borderRadius:"20px", fontWeight:600, flexShrink:0, background: task.badgeType==="required" ? "#3a1206" : "#2a1a04", color: task.badgeType==="required" ? "#e07040" : "#f0c040", border: `0.5px solid ${task.badgeType==="required" ? "#6a2a10" : "#5a3a08"}` }}>
                    {task.badge}
                  </span>
                </div>
              ))}
            </div>
 
            {/* Progress */}
            <div style={{ display:"flex", alignItems:"center", gap:"12px", marginBottom:"32px" }}>
              <div style={{ flex:1, height:"3px", background:"#2a1408", borderRadius:"2px", overflow:"hidden" }}>
                <div style={{ height:"100%", background:"#c04010", borderRadius:"2px", width:`${progress}%`, transition:"width .4s ease" }} />
              </div>
              <p style={{ fontSize:"11px", color:"#7a5a45", letterSpacing:"1px", whiteSpace:"nowrap" }}>{tasksDone} / 3 tasks</p>
            </div>
 
            {/* Section: Details */}
            <p style={{ fontSize:"10px", letterSpacing:"5px", textTransform:"uppercase", color:"#c8a050", fontWeight:600, marginBottom:"16px", display:"flex", alignItems:"center", gap:"14px" }}>
              Your details
              <span style={{ flex:1, height:"0.5px", background:"#2e1a0e" }} />
            </p>
 
            {error && <div style={{ background:"#3a1206", border:"0.5px solid #6a2a10", color:"#e07040", borderRadius:"8px", padding:"14px 16px", fontSize:"13px", marginBottom:"18px", lineHeight:1.6 }}>{error}</div>}
            {info  && <div style={{ background:"#1a1206", border:"0.5px solid #5a3a08", color:"#c8a050", borderRadius:"8px", padding:"14px 16px", fontSize:"13px", marginBottom:"18px", lineHeight:1.6 }}>{info}</div>}
 
            <div style={{ marginBottom:"20px" }}>
              <div style={{ marginBottom:"18px" }}>
                <label style={{ display:"block", fontSize:"9px", letterSpacing:"4px", textTransform:"uppercase", color:"#7a5a45", marginBottom:"8px", fontWeight:600 }}>X (Twitter) handle</label>
                <div style={{ position:"relative", display:"flex", alignItems:"center" }}>
                  <span style={{ position:"absolute", left:"16px", fontSize:"14px", color:"#f0c040", fontWeight:600, pointerEvents:"none" }}>@</span>
                  <input className="pw-input" type="text" placeholder="yourhandle" autoComplete="off" value={twitter} onChange={(e) => setTwitter(e.target.value)} style={{ borderColor: twitterErr ? "#e07040" : undefined }} />
                </div>
                <p style={{ fontSize:"11px", color:"#4a2e1e", marginTop:"6px" }}>Enter without the @ symbol · must match the account that completed the tasks</p>
                {twitterErr && <p style={{ fontSize:"11px", color:"#e07040", marginTop:"5px" }}>Please enter your X handle.</p>}
              </div>
 
              <div style={{ marginBottom:"18px" }}>
                <label style={{ display:"block", fontSize:"9px", letterSpacing:"4px", textTransform:"uppercase", color:"#7a5a45", marginBottom:"8px", fontWeight:600 }}>Wallet address</label>
                <div style={{ position:"relative", display:"flex", alignItems:"center" }}>
                  <span style={{ position:"absolute", left:"16px", fontSize:"12px", color:"#f0c040", fontWeight:600, pointerEvents:"none" }}>◈</span>
                  <input className="pw-input" type="text" placeholder="0x..." autoComplete="off" spellCheck={false} value={wallet} onChange={(e) => setWallet(e.target.value)} style={{ borderColor: walletErr ? "#e07040" : undefined }} />
                </div>
                <p style={{ fontSize:"11px", color:"#4a2e1e", marginTop:"6px" }}>EVM-compatible wallet address</p>
                {walletErr && <p style={{ fontSize:"11px", color:"#e07040", marginTop:"5px" }}>Please enter a valid wallet address.</p>}
              </div>
            </div>
 
            <div style={{ display:"flex", alignItems:"flex-start", gap:"12px", marginBottom:"24px" }}>
              <input type="checkbox" id="agree" checked={agree} onChange={(e) => setAgree(e.target.checked)} style={{ width:"16px", height:"16px", marginTop:"3px", accentColor:"#c04010", flexShrink:0, cursor:"pointer" }} />
              <label htmlFor="agree" style={{ fontSize:"12px", color:"#5a3a28", lineHeight:1.7, cursor:"pointer" }}>
                I confirm I have completed all required tasks and that the wallet and X account above belong to me. I agree to the <a href="#" style={{ color:"#f0c040", textDecoration:"none" }}>terms &amp; conditions</a>.
              </label>
            </div>
 
            <button className="pw-submit" disabled={loading} onClick={handleSubmit}>
              {loading ? <><span className="pw-spinner" />Submitting...</> : "Submit application →"}
            </button>
          </div>
        ) : (
          <div style={{ textAlign:"center", padding:"40px 0 16px" }}>
            <div style={{ fontSize:"44px", color:"#f0c040", marginBottom:"16px" }}>✓</div>
            <p style={{ fontFamily:"'Playfair Display',serif", fontSize:"26px", color:"#fef5e4", marginBottom:"10px", fontWeight:700 }}>You&apos;re in the queue.</p>
            <p style={{ fontSize:"13px", color:"#7a5a45", lineHeight:1.8 }}>
              Your application has been received.<br />
              We&apos;ll announce whitelist results via @Pollosoneth.<br /><br />
              <span style={{ color:"#f0c040" }}>★</span>&nbsp; Quoted the pinned tweet? You&apos;re in line for a guaranteed spot.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}